from docx import Document
from docx.text.paragraph import Paragraph
from copy import deepcopy


PATH = "/Users/oltazagraxha/Desktop/GreenNet/output/doc/RIT_Digital_Institutional_GreenNet_reorganized.docx"


def find_paragraph(doc, text):
    for i, paragraph in enumerate(doc.paragraphs):
        if paragraph.text.strip() == text:
            return i, paragraph
    raise ValueError(f"Paragraph not found: {text!r}")


def insert_paragraph_after(paragraph, text="", style=None):
    new_p = deepcopy(paragraph._p)
    for child in list(new_p):
        new_p.remove(child)
    paragraph._p.addnext(new_p)
    new_para = Paragraph(new_p, paragraph._parent)
    new_para.text = text
    if style:
        new_para.style = style
    return new_para


def move_block_before(start_paragraph, end_paragraph, before_paragraph):
    block = []
    current = start_paragraph._p
    end = end_paragraph._p
    while True:
        nxt = current.getnext()
        block.append(current)
        if current == end:
            break
        current = nxt
    for element in block:
        before_paragraph._p.addprevious(element)


