ref_index, ref_heading = find_paragraph(doc, "References")
references = [
    "Bianzino, A. P., Chaudet, C., Rossi, D., & Rougier, J.-L. (2012). A survey of green networking research. IEEE Communications Surveys & Tutorials, 14(1), 3-20. https://doi.org/10.1109/SURV.2011.113010.00106",
    "Chiaraviglio, L., Mellia, M., & Neri, F. (2009). Reducing power consumption in backbone networks. In 2009 IEEE International Conference on Communications (pp. 1-6). IEEE. https://doi.org/10.1109/ICC.2009.5199404",
    "Gupta, M., & Singh, S. (2003). Greening of the Internet. ACM SIGCOMM Computer Communication Review, 33(4), 19-26. https://doi.org/10.1145/863955.863959",
    "Henderson, T. R., Roy, S., Floyd, S., & Riley, G. F. (2008). ns-3 project goals. In Proceedings of the 2008 Workshop on ns-2: The IP Network Simulator (pp. 13-13). ACM.",
    "International Energy Agency. (2022). Data centres and data transmission networks. https://www.iea.org/reports/data-centres-and-data-transmission-networks",
    "Moy, J. (1998). OSPF version 2 (RFC 2328). IETF. https://www.rfc-editor.org/rfc/rfc2328",
    "Sutton, R. S., & Barto, A. G. (2018). Reinforcement learning: An introduction (2nd ed.). MIT Press.",
    "Valadarsky, A., Schapira, M., Shahaf, D., & Tamar, A. (2017). A machine learning approach to routing. arXiv. https://arxiv.org/abs/1708.03074",
]

current = ref_heading
for entry in references:
    current = insert_paragraph_after(current, entry, "Normal")

# Move references before the appendix so the end matter reads Conclusion -> References -> Appendix.
appendix_index, appendix_heading = find_paragraph(doc, "Appendix: Supporting Figures")
move_block_before(ref_heading, current, appendix_heading)

doc.save(PATH)
